import { RingBuffer } from '../ringBuffer';

describe('RingBuffer', () => {
  it('appends data and reads it back', () => {
    const buf = new RingBuffer();
    buf.append('hello\nworld\n');
    expect(buf.readLines(10)).toContain('hello');
    expect(buf.readLines(10)).toContain('world');
  });

  it('trims buffer when exceeding maxSize', () => {
    const buf = new RingBuffer(10); // 10 char max
    buf.append('12345678901234567890'); // 20 chars
    expect(buf.length).toBeLessThanOrEqual(10);
  });

  it('returns last N lines', () => {
    const buf = new RingBuffer();
    buf.append('line1\nline2\nline3\nline4\nline5\n');
    const result = buf.readLines(2);
    const lines = result.split('\n').filter(Boolean);
    expect(lines).toContain('line4');
    expect(lines).toContain('line5');
    expect(lines).not.toContain('line1');
  });

  it('strips ANSI escape codes', () => {
    const buf = new RingBuffer();
    buf.append('\x1b[31mred text\x1b[0m\n');
    expect(buf.readLines(5)).toBe('red text');
    expect(buf.readLines(5)).not.toContain('\x1b');
  });

  it('returns empty string on empty buffer', () => {
    const buf = new RingBuffer();
    expect(buf.readLines(10)).toBe('');
  });

  it('clamps readLines count to max 500', () => {
    const buf = new RingBuffer();
    buf.append('line\n'.repeat(600));
    const result = buf.readLines(1000);
    const lines = result.split('\n').filter(Boolean);
    expect(lines.length).toBeLessThanOrEqual(500);
  });

  it('clear() resets buffer', () => {
    const buf = new RingBuffer();
    buf.append('some data');
    buf.clear();
    expect(buf.length).toBe(0);
    expect(buf.readLines(10)).toBe('');
  });
});
